func dealsVelocityData(s *store.Store, pipelineFilter string, weeks int, now time.Time) ([]dealsVelocityRow, error) {
	stageNames := map[string]string{}
	pipelines := map[string]dealsVelocityPipeline{}
	metrics := map[string]*dealsVelocityMetric{}
	if err := loadVelocityPipelines(s, pipelineFilter, stageNames, pipelines); err != nil {
		return nil, err
	}
	rows, err := s.Query(`SELECT data FROM deals`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	cutoff := now.AddDate(0, 0, -7*weeks)
	for rows.Next() {
		var raw string
		if err := rows.Scan(&raw); err != nil {
			return nil, err
		}
		var deal struct {
			Properties map[string]string `json:"properties"`
		}
		if json.Unmarshal([]byte(raw), &deal) != nil {
			continue
		}
		pid, sid := deal.Properties["pipeline"], deal.Properties["dealstage"]
		created, ok := parseHubSpotTime(deal.Properties["createdate"])
		if !ok || created.Before(cutoff) || sid == "" || (pipelineFilter != "" && pid != pipelineFilter) {
			continue
		}
		p, ok := pipelines[pid]
		if !ok {
			p = dealsVelocityPipeline{Label: pid, Stages: []string{sid}}
			pipelines[pid] = p
		}
		currentOrder := len(p.Stages)
		for i, stageID := range p.Stages {
			if stageID == sid {
				currentOrder = i
				break
			}
		}
		for i, stageID := range p.Stages {
			key := pid + ":" + stageID
			if metrics[key] == nil {
				metrics[key] = &dealsVelocityMetric{Order: i}
			}
			if i <= currentOrder {
				metrics[key].Entered++
			}
			if i < currentOrder {
				metrics[key].Past++
			}
		}
		key := pid + ":" + sid
		if metrics[key] == nil {
			metrics[key] = &dealsVelocityMetric{Order: currentOrder}
		}
		if stageNames[key] == "" {
			stageNames[key] = sid
		}
		metrics[key].Current++
		metrics[key].SumDays += now.Sub(created).Hours() / 24
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	keys := make([]string, 0, len(metrics))
	for key := range metrics {
		keys = append(keys, key)
	}
	sort.Slice(keys, func(i, j int) bool {
		pi, si, _ := strings.Cut(keys[i], ":")
		pj, sj, _ := strings.Cut(keys[j], ":")
		if pipelines[pi].Label != pipelines[pj].Label {
			return pipelines[pi].Label < pipelines[pj].Label
		}
		if metrics[keys[i]].Order != metrics[keys[j]].Order {
			return metrics[keys[i]].Order < metrics[keys[j]].Order
		}
		return stageNames[pi+":"+si] < stageNames[pj+":"+sj]
	})
	out := make([]dealsVelocityRow, 0, len(keys))
	multi := pipelineFilter == "" && len(pipelines) > 1
	for _, key := range keys {
		pid, sid, _ := strings.Cut(key, ":")
		m, stage := metrics[key], stageNames[key]
		if stage == "" {
			stage = sid
		}
		if multi {
			stage = pipelines[pid].Label + " / " + stage
		}
		avg, conv := 0.0, 0.0
		if m.Current > 0 {
			avg = m.SumDays / float64(m.Current)
		}
		if m.Entered > 0 {
			conv = float64(m.Past) / float64(m.Entered) * 100
		}
		out = append(out, dealsVelocityRow{Stage: stage, AvgDays: avg, CurrentDeals: m.Current, ConversionPct: conv})
	}
	return out, nil
}

func loadVelocityPipelines(s *store.Store, pipelineFilter string, stageNames map[string]string, pipelines map[string]dealsVelocityPipeline) error {
	rows, err := s.Query(`SELECT data FROM pipelines`)
	if err != nil {
		return err
	}
	defer rows.Close()
	for rows.Next() {
		var raw string
		if err := rows.Scan(&raw); err != nil {
			return err
		}
		var p struct {
			ID     string `json:"id"`
			Label  string `json:"label"`
			Stages []struct {
				ID, Label    string
				DisplayOrder int `json:"displayOrder"`
			} `json:"stages"`
		}
		if json.Unmarshal([]byte(raw), &p) != nil || p.ID == "" || (pipelineFilter != "" && p.ID != pipelineFilter) {
			continue
		}
		sort.SliceStable(p.Stages, func(i, j int) bool { return p.Stages[i].DisplayOrder < p.Stages[j].DisplayOrder })
		pipeline := dealsVelocityPipeline{Label: p.Label}
		if pipeline.Label == "" {
			pipeline.Label = p.ID
		}
		for _, st := range p.Stages {
			pipeline.Stages = append(pipeline.Stages, st.ID)
			stageNames[p.ID+":"+st.ID] = st.Label
			if stageNames[p.ID+":"+st.ID] == "" {
				stageNames[p.ID+":"+st.ID] = st.ID
			}
		}
		pipelines[p.ID] = pipeline
	}
	return rows.Err()
}

func parseHubSpotTime(v string) (time.Time, bool) {
	if n, err := strconv.ParseInt(v, 10, 64); err == nil {
		if len(v) >= 13 {
			return time.UnixMilli(n), true
		}
		return time.Unix(n, 0), true
	}
	t, err := time.Parse(time.RFC3339, v)
	return t, err == nil
}

